import{c as e}from"./app.6e7281f6.js";import{_ as c}from"./plugin-vue_export-helper.21dcd24c.js";const o={},d=e('<p>\u77E5\u6211\u8005\u8C13\u6211\u5FC3\u5FE7\uFF0C\u4E0D\u77E5\u6211\u8005\u8C13\u6211\u4F55\u6C42</p><h2 id="\u5F15\u8A00" tabindex="-1"><a class="header-anchor" href="#\u5F15\u8A00" aria-hidden="true">#</a> \u5F15\u8A00</h2><p>\u8BA1\u7B97\u5C5E\u6027\u4F5C\u4E3AVue.js\u7684\u54CD\u5E94\u5F0F\u6838\u5FC3\u4E4B\u4E00\uFF0C\u5728\u9879\u76EE\u5F00\u53D1\u4E2D\u88AB\u9891\u7E41\u4F7F\u7528\u3002\u53EF\u662F\uFF0C\u5728\u8FD9\u4E2A\u7ADE\u4E89\u538B\u529B\u8D8A\u6765\u8D8A\u5927\u7684\u5E74\u4EE3\uFF0C\u4EC5\u6B62\u6B65\u4E8E\u719F\u7EC3\u4F7F\u7528\u662F\u4E07\u4E07\u4E0D\u884C\u7684\uFF0C\u4F60\u53EA\u6709\u638C\u63E1\u5B83\u7684\u5B9E\u73B0\u539F\u7406\u624D\u80FD\u771F\u6B63\u7ACB\u4E8E\u4E0D\u8D25\u4E4B\u5730\u3002</p><blockquote><p>\u5728\u53C2\u770B\u672C\u6587\u4E4B\u524D\uFF0C\u5EFA\u8BAE\u8BFB\u8005\u5BF9Vue.js\u6570\u636E\u54CD\u5E94\u5F0F\u539F\u7406\u6709\u4E00\u5B9A\u7684\u4E86\u89E3\uFF0C\u63A8\u8350\u8F6C\u9605\u7B14\u8005\u524D\u7F6E\u8BFB\u4E66\u7B14\u8BB0\uFF1A</p><ul><li><a href="https://juejin.cn/post/7069312716371918879" target="_blank" rel="noopener noreferrer">Vue.js\u54CD\u5E94\u5F0F\u6570\u636E\u7684\u7B80\u5355\u5B9E\u73B0</a></li><li><a href="https://juejin.cn/post/7069644797778067487" target="_blank" rel="noopener noreferrer">Vue.js\u4E2D\u4E0D\u5BB9\u6613\u7684\u6570\u636E\u54CD\u5E94\u5B9E\u73B0</a></li></ul></blockquote><h2 id="\u8BA1\u7B97\u5C5E\u6027\u7684\u7C7B\u578B\u53CA\u7B80\u5355\u4F7F\u7528" tabindex="-1"><a class="header-anchor" href="#\u8BA1\u7B97\u5C5E\u6027\u7684\u7C7B\u578B\u53CA\u7B80\u5355\u4F7F\u7528" aria-hidden="true">#</a> \u8BA1\u7B97\u5C5E\u6027\u7684\u7C7B\u578B\u53CA\u7B80\u5355\u4F7F\u7528</h2><p>\u5728IT\u9886\u57DF\uFF0C\u6211\u89C9\u5F97\u5B66\u4E60\u4E00\u4E2A\u65B0\u4E8B\u7269\u6700\u597D\u7684\u65B9\u5F0F\u5C31\u662F\u53BB\u770B\u5B83\u7684\u5B98\u7F51\u6587\u6863\u3002\u5728<a href="https://vuejs.org/api/reactivity-core.html#computed" target="_blank" rel="noopener noreferrer">Vue.js 3\u5B98\u65B9\u6587\u6863</a>\u4E2D\u5BF9\u8BA1\u7B97\u5C5E\u6027<code>computed()</code>\u8FDB\u884C\u4E86\u7B80\u5355\u7684\u7C7B\u578B\u53CA\u4F7F\u7528\u4ECB\u7ECD\uFF0C\u5982\u4E0B\uFF1A</p><ul><li>Type</li></ul><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/5860e66cc8094f1c95c1869b3352ef5b~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (72).png"></p><ul><li>Example</li></ul><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/e3401b76178a4bb8bf7ffcf00496c771~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (76).png"></p><p>\u81F3\u6B64\uFF0C\u5373\u4F7F\u4F60\u4ECE\u6CA1\u6709\u7528\u8FC7<code>computed()</code>\uFF0C\u73B0\u5728\u4E5F\u5E94\u8BE5\u5BF9\u5B83\u6709\u4E86\u4E00\u4E2A\u521D\u6B65\u7684\u5370\u8C61\uFF1A\u8BA1\u7B97\u5C5E\u6027\u5206\u4E3A<strong>\u53EA\u8BFB</strong>\u548C<strong>\u53EF\u91CD\u5199</strong>\u4E24\u7C7B\u3002\u4EE5\u53EA\u8BFB\u4E3A\u4F8B\uFF0C\u7528\u6237\u53EF\u4EE5\u901A\u8FC7\u5411<code>computed()</code>\u4F20\u5165\u4E00\u4E2A<code>getter</code>\u51FD\u6570\uFF08<em><code>getter</code>\uFF1A\u5C06\u5BF9\u8C61\u5C5E\u6027\u7ED1\u5B9A\u5230\u67E5\u8BE2\u8BE5\u5C5E\u6027\u65F6\u5C06\u88AB\u8C03\u7528\u7684\u51FD\u6570</em>\uFF09\uFF0C\u4ECE\u800C\u83B7\u5F97\u7ECF\u8FC7\u81EA\u5B9A\u4E49\u903B\u8F91\u8BA1\u7B97\u7684\u8FD4\u56DE\u503C\uFF0C\u5982\u679C\u8BA1\u7B97\u7ED3\u679C\u4F9D\u8D56\u54CD\u5E94\u5F0F\u6570\u636E\uFF0C\u90A3\u4E48\u6BCF\u5F53\u4F9D\u8D56\u7684\u54CD\u5E94\u5F0F\u6570\u636E\u66F4\u65B0\u65F6\uFF0C\u8BA1\u7B97\u5C5E\u6027\u4E5F\u4F1A\u91CD\u65B0\u6267\u884C\u3001\u66F4\u65B0\u3002</p><p>\u63A5\u4E0B\u6765\u8BA9\u6211\u4EEC\u4EE5\u53EA\u8BFB\u8BA1\u7B97\u5C5E\u6027\u4E3A\u4F8B\u56DE\u6EAF\u4E00\u4E0B\u8BA1\u7B97\u5C5E\u6027\u7684\u5B9E\u73B0\u539F\u7406\u3002</p><h2 id="\u4FEE\u6539effect\u4E3A\u61D2\u6267\u884C" tabindex="-1"><a class="header-anchor" href="#\u4FEE\u6539effect\u4E3A\u61D2\u6267\u884C" aria-hidden="true">#</a> \u4FEE\u6539<code>effect</code>\u4E3A\u61D2\u6267\u884C</h2><p>\u65E2\u7136\u8BA1\u7B97\u5C5E\u6027\u4E5F\u5177\u5907\u6570\u636E\u54CD\u5E94\u5F0F\u7684\u7279\u6027\uFF0C\u90A3\u4E48\u5B58\u4E0D\u5B58\u5728\u4E00\u79CD\u53EF\u80FD\uFF1A\u8BA1\u7B97\u5C5E\u6027\u7684\u8BBE\u8BA1\u8005\u5F53\u521D\u5728\u5B9E\u73B0\u8BA1\u7B97\u5C5E\u6027\u7684\u65F6\u5019\uFF0C\u5C31\u53C2\u8003\u4E86\u6570\u636E\u54CD\u5E94\u5F0F\u7684\u5B9E\u73B0\u539F\u7406\u6216\u8005\u8BF4\u5C31\u662F\u5728\u6570\u636E\u54CD\u5E94\u5F0F\u7684\u57FA\u7840\u4E0A\u505A\u4E86\u4E9B\u8BB8\u7684\u5FAE\u8C03\u5462\uFF1F\u8FD9\u5B8C\u5168\u662F\u6709\u53EF\u80FD\u7684\u3002</p><p>\u5047\u8BBE\u6211\u4EEC\u628A\u4F20\u5165<code>effect</code>\u7684\u526F\u4F5C\u7528\u51FD\u6570<code>fn</code>\u770B\u4F5C\u662F\u4E00\u4E2A<code>getter</code>,\u90A3\u4E48\u6BCF\u6B21\u526F\u4F5C\u7528\u51FD\u6570\u7684\u6267\u884C\u90FD\u4F1A\u6267\u884C\u4E00\u6B21<code>getter</code>\uFF0C\u8FDB\u800C\uFF0C\u5982\u679C\u6211\u4EEC\u80FD\u5728\u526F\u4F5C\u7528\u51FD\u6570\u8C03\u7528\u7684\u65F6\u5019\u8FD4\u56DE\u8FD9\u4E2A\u503C\uFF0C\u662F\u4E0D\u662F\u5C31\u6709\u70B9\u50CF\u8BA1\u7B97\u5C5E\u6027\u4E86\u5462\uFF1F\u4F60\u770B\uFF0C\u6B64\u65F6<code>let value = computed(getter)</code>\u548C<code>let value = effect(getter)</code>\u662F\u4E0D\u662F\u5C31\u6709\u70B9\u50CF\uFF1F\u57FA\u4E8E\u4EE5\u4E0A\u601D\u8DEF\uFF0C\u5982\u679C\u6211\u4EEC\u8FD8\u80FD\u591F\u63A7\u5236<code>effect</code>\u51FD\u6570\u7684\u6267\u884C\u65F6\u95F4\uFF0C\u4E0D\u8BA9<code>effect</code>\u51FD\u6570\u7ACB\u5373\u6267\u884C\uFF0C\u800C\u662F\u5728\u9700\u8981\u7684\u4F7F\u7528\u8C03\u7528\uFF0C\u4E0D\u5C31\u7B80\u5355\u5730\u5B9E\u73B0\u4E86\u8BA1\u7B97\u5C5E\u6027<code>computed()</code>\u4E86\u5417\uFF1F</p><p>\u8FDB\u4E00\u6B65\u6765\u770B\uFF0C\u4E3A\u4E86\u5B9E\u73B0\u4E0D\u7ACB\u5373\u6267\u884C\u526F\u4F5C\u7528\u51FD\u6570\uFF0C\u53EF\u4EE5\u5411<code>effect</code>\u7684\u9009\u9879\u53C2\u6570<code>options</code>\u4F20\u5165\u4E00\u4E2A<code>lazy</code>\u5E03\u5C14\u503C\u5C5E\u6027\uFF0C\u5F53<code>lazy === true</code>\uFF0C\u526F\u4F5C\u7528\u51FD\u6570\u5C31\u4E0D\u4F1A\u4E0D\u7ACB\u5373\u6267\u884C\uFF0C\u800C\u662F\u4F5C\u4E3A\u8FD4\u56DE\u503C\u66B4\u9732\u51FA\u6765\uFF0C\u6B64\u65F6<code>effect</code>\u51FD\u6570\u5B9E\u73B0\u4EE3\u7801\u5982\u4E0B\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/f30610ba95b248d0a230d6051251b550~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (81).png"></p><p>\u73B0\u5728\uFF0C\u6211\u4EEC\u5B9E\u73B0\u4E86\u80FD\u591F\u61D2\u6267\u884C\u7684\u526F\u4F5C\u7528\u51FD\u6570\uFF0C\u5E76\u4E14\u80FD\u591F\u62FF\u5230\u526F\u4F5C\u7528\u51FD\u6570\u7684\u6267\u884C\u7ED3\u679C\uFF0C\u62FF\u4E0A\u6587\u7684Vue.js\u5B98\u7F51\u793A\u4F8B\u6253\u4E2A\u6BD4\u65B9\uFF0C\u5C31\u76F8\u5F53\u4E8E\u62FF\u5230\u4E86\u4E00\u4E2A\u8FD4\u56DE<code>const plusOne = computed(() =&gt; count.value + 1)</code>\u4E2D<code>() =&gt; count.value + 1</code>\u7684\u503C\u7684\u51FD\u6570\uFF0C\u63A5\u4E0B\u6765\u53EA\u8981\u521B\u5EFA\u4E00\u4E2A<code>computed()</code>\u51FD\u6570\uFF0C\u5B9E\u73B0\u5BF9<code>plusOne</code>\u7684\u8D4B\u503C\uFF0C\u4ECE\u5F62\u5F0F\u4E0A\u5C31\u597D\u50CF\u7B80\u5355\u5B9E\u73B0\u4E86\u8BA1\u7B97\u5C5E\u6027\uFF0C\u5B9E\u73B0\u4EE3\u7801\u5982\u4E0B\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/a34e7c3e8b0945cfbf4b53aea37b1154~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (79).png"></p><h2 id="\u6027\u80FD\u4F18\u5316-\u6DFB\u52A0\u7F13\u5B58\u529F\u80FD" tabindex="-1"><a class="header-anchor" href="#\u6027\u80FD\u4F18\u5316-\u6DFB\u52A0\u7F13\u5B58\u529F\u80FD" aria-hidden="true">#</a> \u6027\u80FD\u4F18\u5316-\u6DFB\u52A0\u7F13\u5B58\u529F\u80FD</h2><p>\u4E0A\u4E00\u5C0F\u8282\u4E2D\u6211\u4EEC\u5DF2\u7ECF\u7B80\u5355\u5B9E\u73B0\u4E86\u8BA1\u7B97\u5C5E\u6027<code>computed()</code>\uFF0C\u4F46\u662F\u8FD8\u6709\u5F85\u5B8C\u5584\uFF1A\u5206\u6790\u5B9E\u73B0\u7684\u4EE3\u7801\uFF0C\u4F60\u4F1A\u53D1\u73B0\u6BCF\u6B21\u8BFB\u53D6<code>obj.value</code>\u7684\u503C\u90FD\u4F1A\u6267\u884C\u4E00\u6B21\u5B8C\u6574\u7684<code>effectFn</code>\u526F\u4F5C\u7528\u51FD\u6570\u8FDB\u884C\u91CD\u65B0\u8BA1\u7B97\uFF0C\u800C\u5728\u8BA1\u7B97\u5C5E\u6027\u7684\u503C\u4E00\u76F4\u90FD\u6CA1\u6709\u53D8\u5316\u7684\u6761\u4EF6\u4E0B\uFF0C\u8FD9\u79CD\u201C\u53CD\u590D\u8BFB\u53D6\u5C31\u4F1A\u53CD\u590D\u8BA1\u7B97\u201D\u7684\u60C5\u51B5\u663E\u7136\u662F\u4E0D\u5408\u7406\u7684\uFF0C\u56E0\u4E3A\u6B64\u65F6\u8BA1\u7B97\u5C5E\u6027\u7684\u503C\u4E00\u76F4\u90FD\u6CA1\u6709\u53D8\u5316\uFF0C\u4E5F\u5C31\u5B8C\u5168\u6CA1\u6709\u53CD\u590D\u8BA1\u7B97\u7684\u5FC5\u8981\u3002</p><p>\u5176\u5B9E\u89E3\u51B3\u601D\u8DEF\u4E5F\u5F88\u7B80\u5355\uFF0C\u5C31\u50CF\u7528<code>lazy</code>\u6807\u8BB0\u526F\u4F5C\u7528\u51FD\u6570\u662F\u5426\u9700\u8981\u7ACB\u5373\u6267\u884C\u4E00\u6837\uFF0C\u6211\u4EEC\u53EF\u4EE5\u7528\u53D8\u91CF<code>dirty</code>\u6765\u6807\u8BB0\u8BA1\u7B97\u5C5E\u6027\u7684\u503C\u662F\u5426\u9700\u8981\u91CD\u65B0\u8BA1\u7B97\uFF0C\u540C\u65F6\u7528\u53D8\u91CF<code>value</code>\u50A8\u5B58\u7F13\u5B58\u503C\uFF1A\u5982\u679C<code>dirty</code>\u7684\u503C\u4E3A<code>true</code>\uFF0C\u5C31\u8C03\u7528<code>effectFn</code>\u91CD\u65B0\u8BA1\u7B97\u5E76\u66F4\u65B0\u7F13\u5B58\u503C\uFF0C\u540C\u65F6\u4FEE\u6539<code>dirty</code>\u7684\u503C\u4E3A<code>false</code>\uFF1B\u800C\u5982\u679C<code>dirty</code>\u7684\u503C\u4E3A<code>false</code>\uFF0C\u5219\u76F4\u63A5\u8FD4\u56DE\u4E0A\u4E00\u6B21\u7F13\u5B58\u7684\u503C\u5C31\u53EF\u4EE5\u4E86\u3002\u90A3\u4EC0\u4E48\u65F6\u5019\u9700\u8981\u4FEE\u6539<code>dirty</code>\u7684\u503C\u4E3A<code>true</code>\u5462\uFF1F\u5F53\u7136\u662F\u8BA1\u7B97\u5C5E\u6027\u7684\u503C\u53D8\u5316\u7684\u65F6\u5019\u4FEE\u6539\u554A\u3002\u6BD4\u5982\u5728<code>const plusOne = computed(() =&gt; count.value + 1)</code>\u4E4B\u4E2D\uFF0C\u6BCF\u5F53<code>count</code>\u7684\u503C\u53D8\u5316\u5C31\u9700\u8981\u5C06<code>dirty</code>\u7684\u503C\u4FEE\u6539\u4E3A<code>false</code>\uFF0C\u8FD9\u4E2A\u529F\u80FD\u6211\u4EEC\u53EF\u4EE5\u5229\u7528\u8C03\u5EA6\u5668\u51FD\u6570<code>schduler</code>\u6765\u5B9E\u73B0\uFF0C\u5373\u6BCF\u5F53\u8BA1\u7B97\u5C5E\u6027\u6240\u4F9D\u8D56\u7684\u54CD\u5E94\u5F0F\u6570\u636E\u53D8\u5316\u65F6\u5C31\u91CD\u7F6E<code>dirty = true</code>\uFF0C\u5177\u4F53\u4EE3\u7801\u5B9E\u73B0\u5982\u4E0B\uFF1A</p><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/96003af7cca74f5ea7bc76456358402d~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (80).png"></p><h2 id="bug\u89E3\u51B3-\u5D4C\u5957\u8BA1\u7B97\u5C5E\u6027\u5916\u5C42\u54CD\u5E94\u6027\u5931\u6548" tabindex="-1"><a class="header-anchor" href="#bug\u89E3\u51B3-\u5D4C\u5957\u8BA1\u7B97\u5C5E\u6027\u5916\u5C42\u54CD\u5E94\u6027\u5931\u6548" aria-hidden="true">#</a> bug\u89E3\u51B3-\u5D4C\u5957\u8BA1\u7B97\u5C5E\u6027\u5916\u5C42\u54CD\u5E94\u6027\u5931\u6548</h2><p>\u73B0\u5728\uFF0C\u6211\u4EEC\u8BBE\u8BA1\u7684\u8BA1\u7B97\u5C5E\u6027\u5C31\u5DF2\u7ECF\u8D8B\u8FD1\u4E8E\u5B8C\u7F8E\u4E86\uFF0C\u4F46\u662F\u5F53\u51FA\u73B0\u4EE5\u4E0B\u60C5\u51B5\u65F6\uFF0C\u5C31\u66B4\u9732\u51FA\u6765\u4E00\u4E2Abug\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/929a8563aead411e8ca1c86eb9ce75f3~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (84).png"></p><p>\u6211\u4EEC\u671F\u671B\u5F53<code>obj.foo</code>\u81EA\u589E\u65F6\uFF0C\u80FD\u591F\u91CD\u65B0\u6253\u5370<code>sumRes</code>\u7684\u503C\uFF0C\u5C31\u50CF\u5728Vue.js\u4E2D\u4E00\u65E6\u8BA1\u7B97\u5C5E\u6027\u7684\u503C\u53D1\u751F\u53D8\u5316\u5C31\u4F1A\u91CD\u65B0\u6E32\u67D3\uFF0C\u4F46\u662F\u4E8B\u5B9E\u4E0A<code>sumRes</code>\u7684\u503C\u5E76\u6CA1\u6709\u91CD\u65B0\u6253\u5370\u3002\u73B0\u5728\uFF0C\u8BA9\u6211\u4EEC\u6765\u8BD5\u7740\u5206\u6790\u4E00\u4E0B\uFF1A</p><ul><li>\u5F53\u6267\u884C<code>const sumRes = computed(() =&gt; obj.foo + obj.bar)</code>\u65F6\uFF0C<code>obj.foo</code>\u548C<code>obj.bar</code>\u4F1A\u5206\u522B\u4E0E\u8BE5\u526F\u4F5C\u7528\u51FD\u6570\uFF08\u8BA1\u7B97\u5C5E\u6027\u8D4B\u503C\u8868\u8FBE\u5F0F\uFF09\u5EFA\u7ACB\u8054\u7CFB\uFF0C\u5373\u6BCF\u5F53<code>obj.foo</code>\u6216<code>obj.bar</code>\u7684\u503C\u53D1\u751F\u53D8\u5316\u65F6\u90FD\u4F1A\u91CD\u65B0\u8D4B\u503C<code>sumRes</code>\u3002\u6709\u95EE\u9898\u5417\uFF1F\u6CA1\u6709\u554A</li><li>\u518D\u770B<code>effect(() =&gt; { console.log(sumRes.value) })</code>\uFF0C\u8981\u77E5\u9053\uFF1A<code>sumRes</code>\u867D\u7136\u662F\u4E2A\u8BA1\u7B97\u5C5E\u6027\uFF0C\u4F46\u662F\u6B64\u65F6\u8FD8\u5E76\u6CA1\u6709\u505A\u6570\u636E\u4EE3\u7406\uFF0C\u5B83\u672C\u8EAB\u5E76\u4E0D\u662F\u4E00\u4E2A\u54CD\u5E94\u5F0F\u6570\u636E\uFF0C\u6240\u4EE5\u867D\u7136<code>sumRes</code>\u7684\u503C\u53D8\u5316\u4E86\uFF0C\u4F46\u662F\u5E76\u4E0D\u80FD\u91CD\u65B0\u89E6\u53D1<code>console.log(sumRes.value)</code>\u7684\u6267\u884C\uFF0C\u8FD9\u5C31\u662F\u95EE\u9898\u6240\u5728</li></ul><p>\u65E2\u7136\u95EE\u9898\u7684\u6839\u6E90\u627E\u5230\u4E86\uFF0C\u90A3\u73B0\u5728\u5C31\u8BA9\u6211\u4EEC\u6765\u60F3\u4E00\u60F3\u5982\u4F55\u89E3\u51B3\uFF1A\u5DF2\u7ECF\u77E5\u9053\u662F\u56E0\u4E3A<code>sumRes</code>\u4E0D\u5177\u5907\u54CD\u5E94\u6027\uFF0C\u6240\u4EE5\u6BCF\u6B21<code>sumRes</code>\u53D1\u751F\u53D8\u5316\u65F6\u624D\u4E0D\u80FD\u81EA\u52A8\u89E6\u53D1\u76F8\u5173\u4F9D\u8D56\u7684\u526F\u4F5C\u7528\u51FD\u6570\u6267\u884C\u3002\u90A3\u4E48\uFF0C\u6211\u4EEC\u53EF\u4E0D\u53EF\u4EE5\u624B\u52A8\u6A21\u62DF\u4E00\u4E2A<code>Proxy()</code>\u5BF9\u8C61\u4EE3\u7406\uFF1A\u5F53\u8BFB\u53D6<code>sumRes.value</code>\u65F6\uFF0C\u624B\u52A8\u8C03\u7528<code>track</code>\u51FD\u6570\u8FDB\u884C\u8FFD\u8E2A\uFF1B\u5F53<code>sumRes.value</code>\u53D1\u751F\u53D8\u5316\u65F6\uFF0C\u624B\u52A8\u8C03\u7528<code>trigger</code>\u51FD\u6570\u89E6\u53D1\u76F8\u5173\u526F\u4F5C\u7528\u51FD\u6570\u7684\u6267\u884C\u3002\u597D\u50CF\u884C\u5F97\u901A\u54CE\uFF0C\u52A8\u624B\u5B9E\u73B0\u8BD5\u8BD5\uFF1F</p><p>\u5B9E\u73B0\u4EE3\u7801\u5982\u4E0B\uFF1A</p><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/f08b97c5e09e42d2a69996edfa0036f9~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (85).png"></p><h2 id="\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a> \u603B\u7ED3</h2><p>\u8BA1\u7B97\u5C5E\u6027\u5B9E\u73B0\u7684\u5173\u952E\uFF1A</p><ul><li>\u5229\u7528<code>getter</code>\u51FD\u6570\u54CD\u5E94\u8BA1\u7B97\u5C5E\u6027\u7684\u8BFB\u53D6</li><li>\u5229\u7528<code>track</code>\u4E0E<code>trigger</code>\u51FD\u6570\u5B9E\u73B0\u8BA1\u7B97\u5C5E\u6027\u7684\u6570\u636E\u54CD\u5E94\u6027</li></ul><p>\u9644\u5B9E\u73B0\u8BA1\u7B97\u5C5E\u6027\u76F8\u5173\u5B8C\u6574\u4EE3\u7801\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/6c01dc2cfc724016b331da52368fefe9~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (86).png"></p><h2 id="\u58F0\u660E" tabindex="-1"><a class="header-anchor" href="#\u58F0\u660E" aria-hidden="true">#</a> \u58F0\u660E</h2><ul><li>\u672C\u6587\u5C5E\u4E8E\u8BFB\u4E66\u7B14\u8BB0\u4E00\u7C7B\uFF0C\u662F\u4F5C\u8005\u5728\u62DC\u8BFB \u970D\u6625\u9633 \u5927\u4F6C\u7684\u65B0\u4F5C\u300AVue.js\u8BBE\u8BA1\u4E0E\u5B9E\u73B0\u300B\u9014\u4E2D\uFF0C\u4EE5\u4E66\u4E2D\u5185\u5BB9\u4E3A\u84DD\u672C\uFF0C\u8F85\u4EE5\u4E2A\u4EBA\u5FAE\u672B\u7684\u9053\u884C\u201C\u586B\u5199\u201D\u5B8C\u6210\uFF0C\u63A8\u8350\u8D2D\u4E66\u9605\u8BFB\uFF0C\u5B9A\u6709\u6536\u83B7</li><li>\u6B22\u8FCE\u5927\u4F6C\u65A7\u6B63</li><li>\u65E5\u66F4</li></ul><h2 id="\u53C2\u8003\u8D44\u6599" tabindex="-1"><a class="header-anchor" href="#\u53C2\u8003\u8D44\u6599" aria-hidden="true">#</a> \u53C2\u8003\u8D44\u6599</h2><ul><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Functions/get" target="_blank" rel="noopener noreferrer">MDN-getter</a></li></ul>',40);function t(a,r){return d}var u=c(o,[["render",t]]);export{u as default};
